export type JsonRpcId = string | number;

export interface RuntimeDescription {
  providerPackage: string;
  providerVersion: string;
  runtimeType: "transformers-js" | "openai-compatible";
  nodeVersion: string;
  transformersVersion: string | null;
  os: string;
  architecture: string;
  device: string;
  backend: string;
  model: {
    id: string;
    revision: string;
    artifactHash: string;
    tokenizerHash: string;
  };
  embedding: {
    dimensions: number;
    dataType: "float32";
    pooling: string;
    normalize: boolean;
    queryPrefix: string;
    documentPrefix: string;
    maxTokens: number;
    truncation: string;
  };
