import { createHash } from "node:crypto";
import { readdir, readFile, stat } from "node:fs/promises";
import path from "node:path";

export async function hashFile(file: string): Promise<string> {
  return createHash("sha256").update(await readFile(file)).digest("hex");
}

export async function hashArtifacts(root?: string): Promise<string> {
  if (!root) return "unavailable";
  const files: string[] = [];
  async function walk(directory: string): Promise<void> {
    for (const entry of await readdir(directory, { withFileTypes: true })) {
      const full = path.join(directory, entry.name);
      if (entry.isDirectory()) await walk(full);
      else if (entry.isFile()) files.push(full);
    }
  }
  try {
    if (!(await stat(root)).isDirectory()) return hashFile(root);
    await walk(root);
  } catch {
    return "unavailable";
  }
  files.sort();
  const hash = createHash("sha256");
  for (const file of files) {
    hash.update(path.relative(root, file).replaceAll("\\", "/"));
    hash.update("\0");
    hash.update(await readFile(file));
  }
  return hash.digest("hex");
}

export function hashOptions(value: unknown): string {
  return createHash("sha256").update(JSON.stringify(value)).digest("hex");
}

export async function packageLockHash(): Promise<string> {
  const candidates = [new URL("../../package-lock.json", import.meta.url), new URL("../../../package-lock.json", import.meta.url)];
  for (const candidate of candidates) {
    try {
      return createHash("sha256").update(await readFile(candidate)).digest("hex");
    } catch { /* try parent workspace */ }
  }
  return "unavailable";
}

import os from "node:os";
import { hashArtifacts, hashOptions, packageLockHash } from "./runtime.js";
import type { ProviderAdapter, ProviderConfig, RuntimeDescription } from "./types.js";

interface TensorLike { data: Float32Array | number[]; dims?: number[] }
type FeaturePipeline = (input: string | string[], options: Record<string, unknown>) => Promise<TensorLike>;
type GenerationPipeline = (input: string, options: Record<string, unknown>) => Promise<Array<{ generated_text: string }> | { generated_text: string }[]>;

function baseRuntime(config: ProviderConfig, runtimeType: RuntimeDescription["runtimeType"], artifactHash: string, tokenizerHash: string): Promise<RuntimeDescription> {
  return packageLockHash().then(lockfileHash => ({
    providerPackage: "@pma/node-provider",
    providerVersion: "0.1.0",
    runtimeType,
    nodeVersion: process.version,
    transformersVersion: runtimeType === "transformers-js" ? "4.2.0" : null,
    os: os.platform(), architecture: os.arch(), device: config.device ?? "cpu",
    backend: runtimeType === "transformers-js" ? "onnxruntime" : "remote-http",
    model: { id: config.model, revision: config.revision ?? "main", artifactHash, tokenizerHash },
    embedding: {
      dimensions: config.dimensions, dataType: "float32", pooling: config.pooling ?? "mean",
      normalize: config.normalize ?? true, queryPrefix: config.queryPrefix ?? "",
      documentPrefix: config.documentPrefix ?? "", maxTokens: config.maxTokens ?? 512,
      truncation: config.truncation ?? "end"
    },
    lockfileHash,
    optionsHash: hashOptions({ dtype: config.dtype ?? "fp32", localOnly: config.localOnly ?? false,
      baseUrl: config.baseUrl ?? null, generationModel: config.generationModel ?? config.model })
  }));
}

export class TransformersAdapter implements ProviderAdapter {
  private feature?: FeaturePipeline;
  private generator?: GenerationPipeline;
  constructor(private readonly config: ProviderConfig) {}

  private async loadFeature(): Promise<FeaturePipeline> {
    if (!this.feature) {
      const transformers = await import("@huggingface/transformers");
      transformers.env.allowRemoteModels = !(this.config.localOnly ?? false);
      if (this.config.cacheDir) transformers.env.cacheDir = this.config.cacheDir;
      const model = this.config.localModelPath ?? this.config.model;
      this.feature = await transformers.pipeline("feature-extraction", model, {
        revision: this.config.revision ?? "main", device: this.config.device ?? "cpu",
        dtype: this.config.dtype ?? "fp32", local_files_only: this.config.localOnly ?? false
      }) as unknown as FeaturePipeline;
    }
    return this.feature;
  }

  private async loadGenerator(): Promise<GenerationPipeline> {
    if (!this.generator) {
      const transformers = await import("@huggingface/transformers");
      transformers.env.allowRemoteModels = !(this.config.localOnly ?? false);
      if (this.config.cacheDir) transformers.env.cacheDir = this.config.cacheDir;
      const model = this.config.localModelPath ?? this.config.generationModel ?? this.config.model;
      this.generator = await transformers.pipeline("text-generation", model, {
        revision: this.config.revision ?? "main", device: this.config.device ?? "cpu",
        dtype: this.config.dtype ?? "fp32", local_files_only: this.config.localOnly ?? false
      }) as unknown as GenerationPipeline;
    }
    return this.generator;
  }

  async describeRuntime(): Promise<RuntimeDescription> {
    const artifact = await hashArtifacts(this.config.artifactRoot ?? this.config.localModelPath);
    return baseRuntime(this.config, "transformers-js", artifact, artifact);
  }

  private async embed(texts: string[], prefix: string, signal: AbortSignal): Promise<number[][]> {
    if (signal.aborted) throw new DOMException("cancelled", "AbortError");
    const pipeline = await this.loadFeature();
    const output: number[][] = [];
    for (const text of texts) {
      if (signal.aborted) throw new DOMException("cancelled", "AbortError");
      const tensor = await pipeline(prefix + text, { pooling: this.config.pooling ?? "mean",
        normalize: this.config.normalize ?? true });
      output.push(Array.from(tensor.data));
    }
    return output;
  }
  embedDocuments(texts: string[], signal: AbortSignal): Promise<number[][]> {
    return this.embed(texts, this.config.documentPrefix ?? "", signal);
  }
  async embedQuery(text: string, signal: AbortSignal): Promise<number[]> {
    return (await this.embed([text], this.config.queryPrefix ?? "", signal))[0] ?? [];
  }
  async generate(prompt: string, signal: AbortSignal): Promise<string> {
    if (signal.aborted) throw new DOMException("cancelled", "AbortError");
    const pipeline = await this.loadGenerator();
    const output = await pipeline(prompt, { max_new_tokens: 512, do_sample: false, return_full_text: false });
    return output[0]?.generated_text ?? "";
  }
}

export class OpenAIAdapter implements ProviderAdapter {
  constructor(private readonly config: ProviderConfig, private readonly fetchImpl: typeof fetch = fetch) {
    if (!config.baseUrl) throw new Error("baseUrl is required");
  }
  describeRuntime(): Promise<RuntimeDescription> {
    return baseRuntime(this.config, "openai-compatible", "remote-managed", "remote-managed");
  }
  private headers(): Record<string, string> {
    return { "content-type": "application/json", ...(this.config.apiKey ? { authorization: `Bearer ${this.config.apiKey}` } : {}) };
  }
  async embedDocuments(texts: string[], signal: AbortSignal): Promise<number[][]> {
    const response = await this.fetchImpl(`${this.config.baseUrl}/v1/embeddings`, {
      method: "POST", headers: this.headers(), signal,
      body: JSON.stringify({ model: this.config.model, input: texts, dimensions: this.config.dimensions })
    });
    if (!response.ok) throw new Error(`remote embeddings failed (${response.status})`);
    const body = await response.json() as { data?: Array<{ index: number; embedding: number[] }> };
    return (body.data ?? []).sort((a, b) => a.index - b.index).map(item => item.embedding);
  }
  async embedQuery(text: string, signal: AbortSignal): Promise<number[]> {
    return (await this.embedDocuments([text], signal))[0] ?? [];
  }
  async generate(prompt: string, signal: AbortSignal): Promise<string> {
    const response = await this.fetchImpl(`${this.config.baseUrl}/v1/chat/completions`, {
      method: "POST", headers: this.headers(), signal,
      body: JSON.stringify({ model: this.config.generationModel ?? this.config.model,
        messages: [{ role: "user", content: prompt }], temperature: 0 })
    });
    if (!response.ok) throw new Error(`remote generation failed (${response.status})`);
    const body = await response.json() as { choices?: Array<{ message?: { content?: string } }> };
    return body.choices?.[0]?.message?.content ?? "";
  }
}

export function createAdapter(config: ProviderConfig): ProviderAdapter {
  return config.kind === "transformers-js" ? new TransformersAdapter(config) : new OpenAIAdapter(config);
}

import Ajv, { type ErrorObject } from "ajv";

export interface StructuredResult {
  value: unknown;
  raw: string;
  attempts: number;
}

export class StructuredGenerationError extends Error {
  constructor(message: string, readonly raw: string, readonly diagnostics: ErrorObject[] | string[]) {
    super(message);
  }
}

export function extractJson(text: string): unknown {
  for (let start = 0; start < text.length; start++) {
    if (text[start] !== "{" && text[start] !== "[") continue;
    const stack: string[] = [];
    let quoted = false;
    let escaped = false;
    for (let index = start; index < text.length; index++) {
      const character = text[index];
      if (quoted) {
        if (escaped) escaped = false;
        else if (character === "\\") escaped = true;
        else if (character === '"') quoted = false;
        continue;
      }
      if (character === '"') quoted = true;
      else if (character === "{" || character === "[") stack.push(character);
      else if (character === "}" || character === "]") {
        const expected = character === "}" ? "{" : "[";
        if (stack.pop() !== expected) break;
        if (stack.length === 0) {
          try { return JSON.parse(text.slice(start, index + 1)); } catch { break; }
        }
      }
    }
  }
  throw new Error("no JSON value found");
}

export async function generateStructured(
  task: string,
  schema: object,
  generate: (prompt: string) => Promise<string>
): Promise<StructuredResult> {
  const validate = new Ajv({ allErrors: true, strict: false }).compile(schema);
  let feedback = "";
  let lastRaw = "";
  let diagnostics: ErrorObject[] | string[] = [];
  for (let attempt = 1; attempt <= 2; attempt++) {
    const prompt = `${task}\nReturn exactly one JSON value matching this schema:\n${JSON.stringify(schema)}${feedback}`;
    lastRaw = await generate(prompt);
    try {
      const value = extractJson(lastRaw);
      if (validate(value)) return { value, raw: lastRaw, attempts: attempt };
      diagnostics = validate.errors ?? [];
      feedback = `\nPrevious output failed validation: ${JSON.stringify(diagnostics)}. Correct it.`;
    } catch (error) {
      diagnostics = [error instanceof Error ? error.message : "invalid JSON"];
      feedback = `\nPrevious output was not valid JSON: ${diagnostics[0]}. Correct it.`;
    }
  }
  throw new StructuredGenerationError("structured output invalid after retry", lastRaw, diagnostics);
}

import { createAdapter } from "./adapters.js";
import { generateStructured, StructuredGenerationError } from "./structured.js";
import type { JsonRpcId, ProviderAdapter, ProviderConfig } from "./types.js";

type JsonObject = Record<string, unknown>;
interface Request { jsonrpc: "2.0"; id?: JsonRpcId; method: string; params?: JsonObject }

export class ProviderServer {
  private adapter?: ProviderAdapter;
  private shutdown = false;
  private readonly active = new Map<string, AbortController>();

  get shutdownRequested(): boolean { return this.shutdown; }

  async handleLine(line: string): Promise<string | undefined> {
    let request: Request;
    try { request = JSON.parse(line) as Request; }
    catch { return this.error(null, -32700, "PROVIDER_PARSE_ERROR", "invalid JSON"); }
    const id = request?.id ?? null;
    const notification = request?.id === undefined;
    if (!request || request.jsonrpc !== "2.0" || typeof request.method !== "string") {
      return notification ? undefined : this.error(id, -32600, "PROVIDER_INVALID_REQUEST", "invalid JSON-RPC envelope");
    }
    const key = String(id);
    const controller = new AbortController();
    if (!notification) this.active.set(key, controller);
    try {
      const result = await this.dispatch(request.method, request.params ?? {}, controller.signal);
      return notification ? undefined : JSON.stringify({ jsonrpc: "2.0", id, result });
    } catch (error) {
      if (notification) return undefined;
      if (error instanceof StructuredGenerationError) {
        return this.error(id, -32003, "PROVIDER_INVALID_OUTPUT", error.message, false,
          { raw: error.raw, diagnostics: error.diagnostics });
      }
      if (error instanceof DOMException && error.name === "AbortError") {
        return this.error(id, -32800, "PROVIDER_CANCELLED", "request cancelled");
      }
      return this.error(id, -32603, "PROVIDER_INTERNAL", "provider operation failed");
    } finally {
      if (!notification) this.active.delete(key);
    }
  }

  private async dispatch(method: string, params: JsonObject, signal: AbortSignal): Promise<unknown> {
    if (method === "provider.initialize") {
      const config = params.config as ProviderConfig | undefined;
      if (!config || typeof config.kind !== "string" || typeof config.model !== "string" ||
          !Number.isInteger(config.dimensions) || config.dimensions <= 0) throw new Error("invalid config");
      this.adapter = createAdapter(config);
      return { protocolVersion: 1, initialized: true, runtime: await this.adapter.describeRuntime() };
    }
    if (method === "provider.health") return { status: "ok", initialized: Boolean(this.adapter) };
    if (method === "provider.get_capabilities") return {
      methods: ["provider.initialize", "provider.describe_runtime", "provider.get_capabilities",
        "provider.health", "provider.cancel", "provider.shutdown", "embedding.embed_documents",
        "embedding.embed_query", "generation.generate_structured"],
      embeddings: true, structuredGeneration: true, cancellation: true
    };
    if (method === "provider.cancel") {
      const target = params.id;
      if (typeof target !== "string" && typeof target !== "number") throw new Error("invalid cancellation id");
      this.active.get(String(target))?.abort();
      return { cancelled: true };
    }
    if (method === "provider.shutdown") { this.shutdown = true; return { accepted: true }; }
    if (!this.adapter) throw new Error("not initialized");
    if (method === "provider.describe_runtime") return this.adapter.describeRuntime();
    if (method === "embedding.embed_documents") {
      const texts = params.texts;
      if (!Array.isArray(texts) || !texts.every(text => typeof text === "string")) throw new Error("invalid texts");
      return { vectors: await this.adapter.embedDocuments(texts, signal) };
    }
    if (method === "embedding.embed_query") {
      if (typeof params.text !== "string") throw new Error("invalid text");
      return { vector: await this.adapter.embedQuery(params.text, signal) };
    }
    if (method === "generation.generate_structured") {
      if (typeof params.task !== "string" || typeof params.schema !== "object" || params.schema === null)
        throw new Error("invalid structured request");
      return generateStructured(params.task, params.schema as object, prompt => this.adapter!.generate(prompt, signal));
    }
    throw new Error("unknown method");
  }

  private error(id: JsonRpcId | null, rpcCode: number, code: string, message: string,
                retryable = false, details: JsonObject = {}): string {
    return JSON.stringify({ jsonrpc: "2.0", id, error: { code: rpcCode, message,
      data: { code, category: code === "PROVIDER_CANCELLED" ? "cancelled" : "provider", retryable, details } } });
  }
}

import readline from "node:readline";
import { ProviderServer } from "./server.js";

const server = new ProviderServer();
const input = readline.createInterface({ input: process.stdin, crlfDelay: Infinity });
let pending = 0;
input.on("line", line => {
  pending++;
  void server.handleLine(line).then(response => {
    if (response !== undefined) process.stdout.write(`${response}\n`);
    if (server.shutdownRequested) input.close();
  }).catch(error => {
    console.error("provider host failure", error);
    process.exitCode = 1;
    input.close();
  }).finally(() => { pending--; });
});
input.on("close", () => {
  if (pending === 0 && !server.shutdownRequested) process.exitCode = process.exitCode ?? 0;
});

