import { spawn, type ChildProcessWithoutNullStreams } from "node:child_process";
import readline from "node:readline";

export interface RpcClient {
  start(): Promise<void>;
  stop(): Promise<void>;
  request<T = unknown>(method: string, params?: Record<string, unknown>): Promise<T>;
  notify(method: string, params?: Record<string, unknown>): void;
}

interface Pending {
  resolve(value: unknown): void;
  reject(error: Error): void;
}

export class PmaClient implements RpcClient {
  private child?: ChildProcessWithoutNullStreams;
  private nextId = 1;
  private readonly pending = new Map<number, Pending>();
  private stopping = false;

  constructor(private readonly executable: string, private readonly args: string[] = []) {}

  async start(): Promise<void> {
    if (this.child && this.child.exitCode === null) return;
    this.stopping = false;
    const child = spawn(this.executable, this.args, { stdio: ["pipe", "pipe", "pipe"], windowsHide: true });
    this.child = child;
    child.stdin.setDefaultEncoding("utf8");
    const lines = readline.createInterface({ input: child.stdout, crlfDelay: Infinity });
    lines.on("line", line => this.handleLine(line));
    child.on("exit", () => {
      if (this.child === child) this.child = undefined;
      for (const pending of this.pending.values()) pending.reject(new Error("PMA process exited"));
      this.pending.clear();
    });
    await new Promise<void>((resolve, reject) => {
      child.once("spawn", resolve);
      child.once("error", reject);
    });
  }

  async stop(): Promise<void> {
    const child = this.child;
    if (!child) return;
    this.stopping = true;
    try { await this.request("pma.shutdown"); } catch { /* process may already be gone */ }
    child.stdin.end();
    if (child.exitCode === null) {
      await Promise.race([
        new Promise<void>(resolve => child.once("exit", () => resolve())),
        new Promise<void>(resolve => setTimeout(resolve, 1000))
      ]);
    }
    if (child.exitCode === null) child.kill();
    this.child = undefined;
  }

  async request<T = unknown>(method: string, params: Record<string, unknown> = {}): Promise<T> {
    await this.ensureRunning();
    const id = this.nextId++;
    const promise = new Promise<T>((resolve, reject) => {
      this.pending.set(id, { resolve: value => resolve(value as T), reject });
    });
    this.child!.stdin.write(`${JSON.stringify({ jsonrpc: "2.0", id, method, params })}\n`);
    return promise;
  }

  notify(method: string, params: Record<string, unknown> = {}): void {
    if (!this.child || this.child.exitCode !== null) return;
    this.child.stdin.write(`${JSON.stringify({ jsonrpc: "2.0", method, params })}\n`);
  }

  private async ensureRunning(): Promise<void> {
    if (!this.child || this.child.exitCode !== null) {
      if (this.stopping) throw new Error("PMA client is stopping");
      await this.start();
    }
  }

  private handleLine(line: string): void {
    let message: { id?: number; result?: unknown; error?: { message?: string; data?: unknown } };
    try { message = JSON.parse(line) as typeof message; }
    catch { return; }
    if (typeof message.id !== "number") return;
    const pending = this.pending.get(message.id);
    if (!pending) return;
    this.pending.delete(message.id);
    if (message.error) pending.reject(new Error(message.error.message ?? "PMA request failed"));
    else pending.resolve(message.result);
  }
}

import { createHash } from "node:crypto";
import type { RpcClient } from "./client.js";

export interface SessionContext {
  sessionId: string;
  sessionFile?: string;
  cwd: string;
  repository?: string;
  environment: string;
}

export interface MessageLike {
  role: string;
  content?: unknown;
  toolCallId?: string;
  toolName?: string;
  timestamp?: number;
  customType?: string;
  [key: string]: unknown;
}

export interface SliceResult { packet_id?: string; slice?: string; text?: string }

export class LifecycleController {
  private session?: SessionContext;
  private interactionId?: string;
  private interactionSequence = 0;
  private messageOrdinal = 0;
  private cachedSlice = "";
  private cachedPacketId?: string;
  private observationQueue: Promise<void> = Promise.resolve();
  private settled = true;
  private responseModel?: string;

  constructor(private readonly client: RpcClient) {}

  async startSession(context: SessionContext, branchEntries: Array<{ id?: string; message?: MessageLike }> = []): Promise<void> {
    this.session = context;
    await this.client.start();
    await this.safeRequest("pma.initialize", {
      protocol_version: { min: 1, max: 1 }, client: { name: "@pma/pi-adapter", version: "0.1.0" },
      requested_capabilities: ["observation", "recall", "learning"],
      environment: { external_key: context.environment, cwd: context.cwd, repository: context.repository },
      session: { external_key: context.sessionId, source_file: context.sessionFile }
    });
    await this.safeRequest("pma.session.open", {
      session_id: context.sessionId, source_adapter: "pi", source_file: context.sessionFile,
      cwd: context.cwd, repository: context.repository, environment: context.environment
    });
    await this.reconcile(branchEntries);
  }

  async beforeAgentStart(prompt: string): Promise<string> {
    if (!this.session) return "";
    this.interactionSequence++;
    this.messageOrdinal = 0;
    this.interactionId = `${this.session.sessionId}:interaction:${this.interactionSequence}`;
    this.cachedSlice = "";
    this.cachedPacketId = undefined;
    this.settled = false;
    await this.safeRequest("pma.interaction.begin", {
      interaction_id: this.interactionId, session_id: this.session.sessionId,
      prompt, idempotency_key: `${this.interactionId}:begin`, response_model: this.responseModel
    });
    const recall = await this.safeRequest<SliceResult>("pma.recall", {
      packet_id: `${this.interactionId}:packet`, interaction_id: this.interactionId, query: prompt,
      active_contexts: this.activeContexts(), token_budget: 600
    });
    this.cachedSlice = recall?.slice ?? recall?.text ?? "";
    this.cachedPacketId = recall?.packet_id;
    return this.cachedSlice;
  }

  injectContext(messages: MessageLike[]): MessageLike[] {
    const filtered = messages.filter(message => message.customType !== "pma-context");
    if (!this.cachedSlice) return filtered;
    return [...filtered, { role: "custom", customType: "pma-context", content: this.cachedSlice,
      display: false, timestamp: Date.now() }];
  }

  observeMessage(message: MessageLike, sourceEntryId?: string): void {
    if (!this.session || !this.interactionId || message.customType === "pma-context") return;
    const ordinal = this.messageOrdinal++;
    const sourceId = sourceEntryId ?? `${this.interactionId}:message:${ordinal}`;
    const text = messageText(message);
    this.observationQueue = this.observationQueue.then(async () => {
      await this.safeRequest("pma.observe.event", {
        session_id: this.session!.sessionId, interaction_id: this.interactionId,
        source_id: sourceId, parent_source_id: message.toolCallId,
        ordinal, role: message.role, text, tool_name: message.toolName,
        timestamp: message.timestamp, idempotency_key: `pi:${this.session!.environment}:${sourceId}`
      });
    });
  }

  async agentSettled(): Promise<void> {
    if (!this.interactionId || this.settled) return;
    await this.flush();
    await this.safeRequest("pma.interaction.complete", {
      interaction_id: this.interactionId, idempotency_key: `${this.interactionId}:complete`,
      recall_packet_id: this.cachedPacketId
    });
    await this.safeRequest("pma.learning.process_interaction", {
      interaction_id: this.interactionId, idempotency_key: `${this.interactionId}:learn`
    });
    this.settled = true;
    this.cachedSlice = "";
    this.cachedPacketId = undefined;
  }

  async beforeCompaction(summaryEvidence?: string): Promise<void> {
    await this.flush();
    if (summaryEvidence && this.interactionId) {
      this.observeMessage({ role: "custom", content: summaryEvidence, customType: "pi-compaction-summary" });
      await this.flush();
    }
    await this.safeRequest("pma.learning.consolidate", {
      session_id: this.session?.sessionId, reason: "pi_compaction"
    });
  }

  modelSelected(provider: string, model: string): void {
    this.responseModel = `${provider}/${model}`;
    if (this.session) this.client.notify("pma.observe.event", {
      session_id: this.session.sessionId, role: "model_provenance", text: this.responseModel,
      source_id: `${this.session.sessionId}:model:${Date.now()}`
    });
  }

  async shutdown(): Promise<void> {
    await this.flush();
    await this.safeRequest("pma.session.close", { session_id: this.session?.sessionId });
    await this.client.stop();
    this.session = undefined;
  }

  async flush(): Promise<void> { await this.observationQueue; }
  get currentSlice(): string { return this.cachedSlice; }
  get currentInteractionId(): string | undefined { return this.interactionId; }

  private activeContexts(): Array<{ type: string; external_key: string }> {
    if (!this.session) return [];
    return [
      { type: "repository", external_key: this.session.repository ?? this.session.cwd },
      { type: "environment", external_key: this.session.environment },
      { type: "session", external_key: this.session.sessionId }
    ];
  }

  private async reconcile(entries: Array<{ id?: string; message?: MessageLike }>): Promise<void> {
    for (const entry of entries) {
      if (!entry.message || !entry.id) continue;
      await this.safeRequest("pma.observe.event", {
        session_id: this.session?.sessionId, source_id: entry.id, role: entry.message.role,
        text: messageText(entry.message), idempotency_key: `pi:reconcile:${entry.id}`
      });
    }
  }

  private async safeRequest<T = unknown>(method: string, params: Record<string, unknown>): Promise<T | undefined> {
    try { return await this.client.request<T>(method, compact(params)); }
    catch { return undefined; }
  }
}

function compact(value: Record<string, unknown>): Record<string, unknown> {
  return Object.fromEntries(Object.entries(value).filter(([, item]) => item !== undefined));
}

export function messageText(message: MessageLike): string {
  if (typeof message.content === "string") return message.content;
  if (!Array.isArray(message.content)) return "";
  return message.content.map(block => {
    if (!block || typeof block !== "object") return "";
    const value = block as Record<string, unknown>;
    if (value.type === "text") return String(value.text ?? "");
    if (value.type === "thinking") return String(value.thinking ?? "");
    if (value.type === "toolCall") return `[tool ${String(value.name ?? "unknown")}] ${JSON.stringify(value.arguments ?? {})}`;
    if (value.type === "image") return "[image]";
    return "";
  }).filter(Boolean).join("\n");
}

export function environmentKey(): string {
  return createHash("sha256").update(`${process.platform}:${process.arch}:${process.env.COMPUTERNAME ?? process.env.HOSTNAME ?? "host"}`)
    .digest("hex").slice(0, 24);
}

import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { resolve } from "node:path";
import { LifecycleController, environmentKey, type MessageLike } from "./controller.js";
import { PmaClient } from "./client.js";

export const adapterPackageName = "@pma/pi-adapter";
const promptFragment = "PMA supplies recalled context automatically. Use PMA tools only for explicit recall, durable learning, correction, or inspection; current user instructions always take priority.";

export default function pmaExtension(pi: ExtensionAPI): void {
  const executable = process.env.PMA_CORE_PATH ?? "pma-core";
  const client = new PmaClient(executable);
  const controller = new LifecycleController(client);

  pi.on("session_start", async (_event, ctx) => {
    let repository: string | undefined;
    const remote = await pi.exec("git", ["config", "--get", "remote.origin.url"], { cwd: ctx.cwd });
    if (remote.code === 0) repository = remote.stdout.trim() || undefined;
    await controller.startSession({
      sessionId: ctx.sessionManager.getSessionId(),
      sessionFile: ctx.sessionManager.getSessionFile(),
      cwd: ctx.cwd,
      repository,
      environment: environmentKey()
    }, ctx.sessionManager.getBranch().map(entry => ({
      id: "id" in entry ? entry.id : undefined,
      message: entry.type === "message" ? entry.message as MessageLike : undefined
    })));
    if (ctx.hasUI) ctx.ui.setStatus("pma", "PMA ready");
  });

  pi.on("input", event => {
    if (event.source === "extension") return { action: "continue" as const };
    return { action: "continue" as const };
  });

  pi.on("before_agent_start", async (event) => {
    const slice = await controller.beforeAgentStart(event.prompt);
    return {
      ...(slice ? { message: { customType: "pma-context", content: slice, display: false } } : {}),
      systemPrompt: `${event.systemPrompt}\n\n${promptFragment}`
    };
  });

  pi.on("context", event => ({
    messages: controller.injectContext(event.messages as MessageLike[]) as typeof event.messages
  }));

  pi.on("message_end", (event, ctx) => {
    controller.observeMessage(event.message as MessageLike, ctx.sessionManager.getLeafId() ?? undefined);
  });

  pi.on("turn_end", event => {
    for (const result of event.toolResults) controller.observeMessage(result as MessageLike);
  });

  pi.on("agent_settled", async () => { await controller.agentSettled(); });

  pi.on("session_before_compact", async event => {
    await controller.beforeCompaction(event.preparation.previousSummary);
  });

  pi.on("model_select", event => {
    controller.modelSelected(event.model.provider, event.model.id);
  });

  pi.on("session_shutdown", async (_event, ctx) => {
    await controller.shutdown();
    if (ctx.hasUI) ctx.ui.setStatus("pma", undefined);
  });

  registerTools(pi, client);
  registerCommands(pi, client);
}

function registerTools(pi: ExtensionAPI, client: PmaClient): void {
  pi.registerTool({
    name: "pma_recall",
    label: "Recall Memory",
    description: "Explicitly search persistent memory when automatic context is insufficient.",
    promptSnippet: "Search PMA persistent memory",
    parameters: Type.Object({ query: Type.String(), limit: Type.Optional(Type.Number()) }),
    async execute(_id, params) {
      const result = await client.request("pma.recall", { query: params.query, selected_limit: params.limit ?? 10 });
      return textResult(result);
    }
  });
  pi.registerTool({
    name: "pma_learn",
    label: "Learn Memory",
    description: "Explicitly propose a durable statement backed by the current interaction.",
    parameters: Type.Object({ statement: Type.String(), authority: Type.Optional(Type.String()) }),
    async execute(_id, params) {
      const result = await client.request("pma.learning.propose", {
        statement: params.statement, authority: params.authority ?? "explicit_user"
      });
      return textResult(result);
    }
  });
  pi.registerTool({
    name: "pma_correct",
    label: "Correct Memory",
    description: "Record an explicit correction while preserving prior memory history.",
    parameters: Type.Object({ target: Type.String(), correction: Type.String() }),
    async execute(_id, params) {
      const result = await client.request("pma.memory.propose_correction", params);
      return textResult(result);
    }
  });
  pi.registerTool({
    name: "pma_inspect",
    label: "Inspect Memory",
    description: "Inspect one persistent memory and its provenance.",
    parameters: Type.Object({ id: Type.String() }),
    async execute(_id, params) {
      const result = await client.request("pma.memory.get", params);
      return textResult(result);
    }
  });
}

function registerCommands(pi: ExtensionAPI, client: PmaClient): void {
  pi.registerCommand("pma-status", {
    description: "Show PMA-Core status",
    handler: async (_args, ctx) => {
      try {
        const status = await client.request("pma.get_status");
        ctx.ui.notify(JSON.stringify(status), "info");
      } catch (error) {
        ctx.ui.notify(error instanceof Error ? error.message : "PMA unavailable", "error");
      }
    }
  });
  pi.registerCommand("pma-recall", {
    description: "Explicitly query PMA memory",
    handler: async (args, ctx) => {
      if (!args.trim()) return;
      try {
        const result = await client.request("pma.recall", { query: args.trim() });
        ctx.ui.notify(JSON.stringify(result), "info");
      } catch (error) {
        ctx.ui.notify(error instanceof Error ? error.message : "Recall failed", "error");
      }
    }
  });
}

function textResult(value: unknown): { content: Array<{ type: "text"; text: string }>; details: unknown } {
  const text = typeof value === "string" ? value : JSON.stringify(value, null, 2);
  return { content: [{ type: "text", text }], details: value };
}

export function defaultCorePath(cwd: string): string {
  return process.env.PMA_CORE_PATH ?? resolve(cwd, "build", "windows-msvc-release", "Release", "pma-core.exe");
}

