{
  "name": "@pma/mcp-adapter",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "bin": { "pma-mcp": "dist/src/cli.js" },
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "test": "npm run build && node --test dist/test/mcp.test.js"
  },
  "engines": { "node": ">=24 <25" },
  "devDependencies": { "typescript": "5.8.3", "@types/node": "24.0.0" }
}

{
  "compilerOptions": {
    "target": "ES2022", "module": "NodeNext", "moduleResolution": "NodeNext",
    "rootDir": ".", "outDir": "dist", "strict": true, "noUncheckedIndexedAccess": true,
    "exactOptionalPropertyTypes": true, "forceConsistentCasingInFileNames": true,
    "skipLibCheck": true
  },
  "include": ["src/**/*.ts", "test/**/*.ts"]
}

import { spawn, type ChildProcessWithoutNullStreams } from "node:child_process";
import readline from "node:readline";

export interface PmaService {
  request<T = unknown>(method: string, params?: Record<string, unknown>): Promise<T>;
  close(): Promise<void>;
}

export class ChildPmaService implements PmaService {
  private child: ChildProcessWithoutNullStreams | undefined;
  private nextId = 1;
  private readonly pending = new Map<number, { resolve(value: unknown): void; reject(error: Error): void }>();
  constructor(private readonly command: string, private readonly args: string[] = []) {}

  async start(initialize: Record<string, unknown>): Promise<void> {
    if (this.child?.exitCode === null) return;
    const child = spawn(this.command, this.args, { stdio: ["pipe", "pipe", "pipe"], windowsHide: true });
    this.child = child;
    child.stdin.setDefaultEncoding("utf8");
    readline.createInterface({ input: child.stdout, crlfDelay: Infinity }).on("line", line => this.onLine(line));
    child.on("exit", () => {
      if (this.child === child) this.child = undefined;
      for (const pending of this.pending.values()) pending.reject(new Error("PMA service exited"));
      this.pending.clear();
    });
    await new Promise<void>((resolve, reject) => { child.once("spawn", resolve); child.once("error", reject); });
    await this.request("pma.initialize", initialize);
  }

  async request<T = unknown>(method: string, params: Record<string, unknown> = {}): Promise<T> {
    if (!this.child || this.child.exitCode !== null) throw new Error("PMA service unavailable");
    const id = this.nextId++;
    const result = new Promise<T>((resolve, reject) => this.pending.set(id, {
      resolve: value => resolve(value as T), reject
    }));
    this.child.stdin.write(`${JSON.stringify({ jsonrpc: "2.0", id, method, params })}\n`);
    return result;
  }

  async close(): Promise<void> {
    const child = this.child;
    if (!child) return;
    try { await this.request("pma.shutdown"); } catch { /* already stopped */ }
    child.stdin.end();
    if (child.exitCode === null) await Promise.race([
      new Promise<void>(resolve => child.once("exit", () => resolve())),
      new Promise<void>(resolve => setTimeout(resolve, 1000))
    ]);
    if (child.exitCode === null) child.kill();
    this.child = undefined;
  }

  private onLine(line: string): void {
    let response: { id?: number; result?: unknown; error?: { message?: string; data?: unknown } };
    try { response = JSON.parse(line) as typeof response; } catch { return; }
    if (typeof response.id !== "number") return;
    const pending = this.pending.get(response.id);
    if (!pending) return;
    this.pending.delete(response.id);
    if (response.error) pending.reject(new Error(response.error.message ?? "PMA request failed"));
    else pending.resolve(response.result);
  }
}

export const protocolVersion = "2025-11-25";
export const promptFragment = "Persistent memory is available through PMA tools. Recalled memories may be uncertain or historical; current explicit user corrections always take priority. Use pma_learn only for durable decisions, corrections, reusable procedures, or unresolved goals—not transient conversation.";

const object = (properties: Record<string, unknown>, required: string[] = []) => ({
  type: "object", properties, required, additionalProperties: false
});
const string = { type: "string", minLength: 1 };

export const safeTools = [
  { name: "pma_get_context", description: "Recall compact persistent context before work that may depend on prior decisions, or after host compaction. This is explicit MCP recall, not guaranteed automatic injection.", inputSchema: object({ query: string, token_budget: { type: "integer", minimum: 32, maximum: 4000 } }, ["query"]) },
  { name: "pma_recall", description: "Search durable PMA knowledge. Results may include uncertain or historical memories and never override current user instructions.", inputSchema: object({ query: string, limit: { type: "integer", minimum: 1, maximum: 50 } }, ["query"]) },
  { name: "pma_search_memories", description: "Search validated durable memories by text; this does not search transient conversation state.", inputSchema: object({ query: string, limit: { type: "integer", minimum: 1, maximum: 50 } }, ["query"]) },
  { name: "pma_get_memory", description: "Inspect one durable memory, including current status and provenance identifiers.", inputSchema: object({ id: string }, ["id"]) },
  { name: "pma_remember", description: "Submit an explicit durable statement as evidence and a validated PMA proposal. It does not bypass validation or directly grant authority.", inputSchema: object({ statement: string }, ["statement"]) },
  { name: "pma_learn", description: "Propose durable learning after a decision, correction, reusable procedure, changed assumption, or unresolved goal. Never use for transient details; validation remains mandatory.", inputSchema: object({ statement: string, authority: { type: "string" } }, ["statement"]) },
  { name: "pma_propose_correction", description: "Correct a durable memory while preserving its prior claim and source history.", inputSchema: object({ target: string, correction: string }, ["target", "correction"]) },
  { name: "pma_prepare_compaction", description: "Flush important durable state before host compaction. MCP cannot detect compaction automatically, so the host or model must call this explicitly.", inputSchema: object({ summary: { type: "string" } }) },
  { name: "pma_restore_after_compaction", description: "Recall restoration context after host compaction. This explicit MCP call cannot guarantee automatic restoration.", inputSchema: object({ query: { type: "string" } }) }
] as const;

export const administrativeTools = [
  { name: "pma_delete_evidence", description: "Administrative permanent evidence deletion. Disabled unless explicitly configured.", inputSchema: object({ id: string, confirmation: string }, ["id", "confirmation"]) },
  { name: "pma_rebuild_vectors", description: "Administrative vector rebuild. Disabled unless explicitly configured.", inputSchema: object({ profile_id: string }, ["profile_id"]) },
  { name: "pma_change_provider", description: "Administrative provider change. Disabled unless explicitly configured.", inputSchema: object({ provider_id: string }, ["provider_id"]) }
] as const;

import { administrativeTools, promptFragment, protocolVersion, safeTools } from "./catalog.js";
import type { PmaService } from "./pma-client.js";

type Id = string | number | null;
type Params = Record<string, unknown>;
interface Request { jsonrpc: "2.0"; id?: string | number; method: string; params?: Params }

export class McpServer {
  private initialized = false;
  constructor(private readonly pma: PmaService, private readonly allowAdministrative = false) {}

  async handleLine(line: string): Promise<string | undefined> {
    let request: Request;
    try { request = JSON.parse(line) as Request; }
    catch { return error(null, -32700, "Parse error"); }
    const notification = request?.id === undefined;
    const id = request?.id ?? null;
    if (!request || request.jsonrpc !== "2.0" || typeof request.method !== "string")
      return notification ? undefined : error(id, -32600, "Invalid Request");
    try {
      const result = await this.dispatch(request.method, request.params ?? {});
      return notification ? undefined : JSON.stringify({ jsonrpc: "2.0", id, result });
    } catch (caught) {
      if (notification) return undefined;
      const issue = caught instanceof McpError ? caught : new McpError(-32603, "Internal error");
      return error(id, issue.code, issue.message, issue.data);
    }
  }

  private async dispatch(method: string, params: Params): Promise<unknown> {
    if (method === "initialize") {
      const requested = params.protocolVersion;
      if (typeof requested !== "string") throw new McpError(-32602, "protocolVersion is required");
      this.initialized = true;
      return {
        protocolVersion,
        capabilities: { tools: { listChanged: false }, resources: { subscribe: false, listChanged: false }, prompts: { listChanged: false } },
        serverInfo: { name: "@pma/mcp-adapter", version: "0.1.0" },
        instructions: promptFragment
      };
    }
    if (method === "notifications/initialized" || method === "notifications/cancelled") return {};
    if (!this.initialized) throw new McpError(-32002, "MCP server is not initialized");
    if (method === "ping") return {};
    if (method === "tools/list") return { tools: this.allowAdministrative ? [...safeTools, ...administrativeTools] : safeTools };
    if (method === "tools/call") return this.callTool(params);
    if (method === "resources/list") return { resources: [
      { uri: "pma://status", name: "PMA status", mimeType: "application/json", description: "Current PMA service status" }
    ] };
    if (method === "resources/templates/list") return { resourceTemplates: [
      { uriTemplate: "pma://memory/{id}", name: "PMA memory", mimeType: "application/json", description: "Inspectable durable memory by ID" }
    ] };
    if (method === "resources/read") return this.readResource(params);
    if (method === "prompts/list") return { prompts: [
      { name: "pma-memory-guidance", description: "Safe guidance for explicit persistent-memory use", arguments: [] }
    ] };
    if (method === "prompts/get") {
      if (params.name !== "pma-memory-guidance") throw new McpError(-32602, "Unknown prompt");
      return { description: "PMA persistent-memory guidance", messages: [
        { role: "user", content: { type: "text", text: promptFragment } }
      ] };
    }
    throw new McpError(-32601, "Method not found");
  }

  private async callTool(params: Params): Promise<unknown> {
    if (typeof params.name !== "string") throw new McpError(-32602, "Tool name is required");
    const args = isObject(params.arguments) ? params.arguments : {};
    const safe = safeTools.find(tool => tool.name === params.name);
    const administrative = administrativeTools.find(tool => tool.name === params.name);
    if (administrative && !this.allowAdministrative)
      throw new McpError(-32003, "Administrative PMA tool is disabled", { code: "PMA_PERMISSION_DENIED" });
    if (!safe && !administrative) throw new McpError(-32602, "Unknown tool");
    const schema = (safe ?? administrative)!.inputSchema;
    validate(schema as Schema, args);
    let result: unknown;
    switch (params.name) {
      case "pma_get_context":
        result = await this.pma.request("pma.recall", { query: args.query, token_budget: args.token_budget ?? 600 });
        break;
      case "pma_recall":
      case "pma_search_memories":
        result = await this.pma.request("pma.memory.search", { query: args.query, selected_limit: args.limit ?? 10 });
        break;
      case "pma_get_memory":
        result = await this.pma.request("pma.memory.get", { id: args.id });
        break;
      case "pma_remember":
      case "pma_learn":
        result = await this.pma.request("pma.learning.propose", {
          statement: args.statement, authority: args.authority ?? "explicit_mcp"
        });
        break;
      case "pma_propose_correction":
        result = await this.pma.request("pma.memory.propose_correction", { target: args.target, correction: args.correction });
        break;
      case "pma_prepare_compaction":
        result = await this.pma.request("pma.learning.consolidate", { reason: "mcp_compaction", summary: args.summary });
        break;
      case "pma_restore_after_compaction":
        result = await this.pma.request("pma.recall", { query: args.query ?? "active goals decisions unresolved work", token_budget: 1000 });
        break;
      default:
        throw new McpError(-32601, "Administrative operation is not implemented by this adapter");
    }
    const text = bounded(JSON.stringify(result, null, 2));
    return { content: [{ type: "text", text }], structuredContent: result, isError: false };
  }

  private async readResource(params: Params): Promise<unknown> {
    if (typeof params.uri !== "string") throw new McpError(-32602, "Resource URI is required");
    let value: unknown;
    if (params.uri === "pma://status") value = await this.pma.request("pma.get_status");
    else {
      const match = /^pma:\/\/memory\/([^/]+)$/.exec(params.uri);
      if (!match) throw new McpError(-32002, "Resource not found");
      value = await this.pma.request("pma.memory.get", { id: decodeURIComponent(match[1] ?? "") });
    }
    return { contents: [{ uri: params.uri, mimeType: "application/json", text: bounded(JSON.stringify(value, null, 2)) }] };
  }
}

class McpError extends Error {
  constructor(readonly code: number, message: string, readonly data?: unknown) { super(message); }
}

interface Schema { properties: Record<string, { type?: string }>; required?: readonly string[]; additionalProperties?: boolean }
function validate(schema: Schema, args: Params): void {
  for (const field of schema.required ?? []) {
    if (!(field in args) || args[field] === "") throw new McpError(-32602, `Missing required field: ${field}`);
  }
  if (schema.additionalProperties === false) {
    for (const field of Object.keys(args)) if (!(field in schema.properties)) throw new McpError(-32602, `Unknown field: ${field}`);
  }
  for (const [field, value] of Object.entries(args)) {
    const expected = schema.properties[field]?.type;
    if (expected === "string" && typeof value !== "string") throw new McpError(-32602, `Invalid field type: ${field}`);
    if (expected === "integer" && !Number.isInteger(value)) throw new McpError(-32602, `Invalid field type: ${field}`);
  }
}
function isObject(value: unknown): value is Params { return Boolean(value) && typeof value === "object" && !Array.isArray(value); }
function bounded(text: string): string { return text.length <= 50_000 ? text : `${text.slice(0, 50_000)}\n[truncated]`; }
function error(id: Id, code: number, message: string, data?: unknown): string {
  return JSON.stringify({ jsonrpc: "2.0", id, error: { code, message, ...(data === undefined ? {} : { data }) } });
}

import { existsSync } from "node:fs";
import { mkdir } from "node:fs/promises";
import path from "node:path";
import readline from "node:readline";
import { ChildPmaService } from "./pma-client.js";
import { McpServer } from "./server.js";

const cwd = process.cwd();
const localCore = process.platform === "win32"
  ? path.join(cwd, "build", "windows-msvc-release", "Release", "pma-core.exe")
  : path.join(cwd, "build", "linux-gcc-release", "pma-core");
const executable = process.env.PMA_CORE_PATH ?? (existsSync(localCore) ? localCore : "pma-core");
const bundleRoot = process.env.PMA_BUNDLE_ROOT ?? path.join(cwd, ".pma");
await mkdir(bundleRoot, { recursive: true });
const pma = new ChildPmaService(executable);
await pma.start({
  protocol_version: { min: 1, max: 1 }, client: { name: "@pma/mcp-adapter", version: "0.1.0" },
  requested_capabilities: ["recall", "learning", "inspection"],
  database_path: process.env.PMA_DATABASE_PATH ?? path.join(bundleRoot, "pma.sqlite"),
  bundle_root: bundleRoot
});
const server = new McpServer(pma, process.env.PMA_MCP_ALLOW_ADMIN === "1");
const lines = readline.createInterface({ input: process.stdin, crlfDelay: Infinity });
const pending = new Set<Promise<void>>();
lines.on("line", line => {
  const operation = server.handleLine(line).then(response => {
    if (response !== undefined) process.stdout.write(`${response}\n`);
  }).catch(error => {
    console.error("MCP adapter internal failure", error);
    process.exitCode = 1;
  }).finally(() => pending.delete(operation));
  pending.add(operation);
});
lines.on("close", () => { void Promise.allSettled([...pending]).then(() => pma.close()); });

import assert from "node:assert/strict";
import { spawn } from "node:child_process";
import { once } from "node:events";
import { mkdtemp, rm } from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import readline from "node:readline";
import test from "node:test";
import { McpServer } from "../src/server.js";
import type { PmaService } from "../src/pma-client.js";

class MockPma implements PmaService {
  calls: Array<{ method: string; params?: Record<string, unknown> }> = [];
  async request<T>(method: string, params?: Record<string, unknown>): Promise<T> {
    this.calls.push(params ? { method, params } : { method });
    return { method, ...params } as T;
  }
  async close(): Promise<void> {}
}

async function send(server: McpServer, id: number, method: string, params: Record<string, unknown> = {}) {
  const line = await server.handleLine(JSON.stringify({ jsonrpc: "2.0", id, method, params }));
  assert.ok(line);
  return JSON.parse(line) as Record<string, any>;
}
async function initialize(server: McpServer) {
  return send(server, 1, "initialize", { protocolVersion: "2025-11-25", capabilities: {},
    clientInfo: { name: "test", version: "1" } });
}

test("MCP initialization exposes versioned safe capabilities", async () => {
  const pma = new MockPma();
  const server = new McpServer(pma);
  const response = await initialize(server);
  assert.equal(response.result.protocolVersion, "2025-11-25");
  assert.match(response.result.instructions, /current explicit user corrections/);
  const tools = await send(server, 2, "tools/list");
  assert.ok(tools.result.tools.some((tool: { name: string }) => tool.name === "pma_learn"));
  assert.ok(!tools.result.tools.some((tool: { name: string }) => tool.name === "pma_delete_evidence"));
  const resources = await send(server, 3, "resources/templates/list");
  assert.equal(resources.result.resourceTemplates[0].uriTemplate, "pma://memory/{id}");
});

test("safe tools validate and translate into PMA services", async () => {
  const pma = new MockPma();
  const server = new McpServer(pma);
  await initialize(server);
  const learned = await send(server, 2, "tools/call", { name: "pma_learn",
    arguments: { statement: "SQLite is authoritative", authority: "explicit_user" } });
  assert.equal(learned.result.isError, false);
  assert.deepEqual(pma.calls.at(-1), { method: "pma.learning.propose",
    params: { statement: "SQLite is authoritative", authority: "explicit_user" } });
  const invalid = await send(server, 3, "tools/call", { name: "pma_learn", arguments: {} });
  assert.equal(invalid.error.code, -32602);
  const unknown = await send(server, 4, "tools/call", { name: "pma_recall",
    arguments: { query: "x", surprise: true } });
  assert.equal(unknown.error.code, -32602);
});

test("administrative tools are denied by default", async () => {
  const server = new McpServer(new MockPma());
  await initialize(server);
  const response = await send(server, 2, "tools/call", { name: "pma_delete_evidence",
    arguments: { id: "evidence:1", confirmation: "yes" } });
  assert.equal(response.error.code, -32003);
  assert.equal(response.error.data.code, "PMA_PERMISSION_DENIED");
});

test("resources and compaction tools preserve explicit MCP semantics", async () => {
  const pma = new MockPma();
  const server = new McpServer(pma);
  await initialize(server);
  const resource = await send(server, 2, "resources/read", { uri: "pma://memory/claim%3A1" });
  assert.equal(resource.result.contents[0].mimeType, "application/json");
  assert.deepEqual(pma.calls.at(-1), { method: "pma.memory.get", params: { id: "claim:1" } });
  await send(server, 3, "tools/call", { name: "pma_prepare_compaction", arguments: { summary: "state" } });
  assert.equal(pma.calls.at(-1)?.method, "pma.learning.consolidate");
  await send(server, 4, "tools/call", { name: "pma_restore_after_compaction", arguments: {} });
  assert.equal(pma.calls.at(-1)?.method, "pma.recall");
});

test("stdio MCP host performs real learn recall and resource inspection", async () => {
  const root = await mkdtemp(path.join(os.tmpdir(), "pma-mcp-e2e-"));
  const core = path.resolve(process.cwd(), "..", "..", "build", "windows-msvc-release", "Release", "pma-core.exe");
  const cli = path.resolve(process.cwd(), "dist", "src", "cli.js");
  const child = spawn(process.execPath, [cli], { stdio: ["pipe", "pipe", "pipe"],
    env: { ...process.env, PMA_CORE_PATH: core, PMA_BUNDLE_ROOT: root } });
  child.stdin.setDefaultEncoding("utf8");
  let stderr = "";
  child.stderr.setEncoding("utf8");
  child.stderr.on("data", chunk => { stderr += chunk; });
  const lines = readline.createInterface({ input: child.stdout, crlfDelay: Infinity });
  const waiters: Array<(value: any) => void> = [];
  lines.on("line", line => waiters.shift()?.(JSON.parse(line)));
  const request = (id: number, method: string, params: Record<string, unknown> = {}) =>
    new Promise<any>(resolve => { waiters.push(resolve); child.stdin.write(`${JSON.stringify({ jsonrpc: "2.0", id, method, params })}\n`); });
  assert.equal((await request(1, "initialize", { protocolVersion: "2025-11-25",
    clientInfo: { name: "e2e", version: "1" }, capabilities: {} })).result.protocolVersion, "2025-11-25");
  const learned = await request(2, "tools/call", { name: "pma_learn",
    arguments: { statement: "MCP explicit memory survives" } });
  assert.equal(learned.result.isError, false);
  const claimId = learned.result.structuredContent.claim_id as string;
  const memory = await request(3, "resources/read", { uri: `pma://memory/${encodeURIComponent(claimId)}` });
  assert.match(memory.result.contents[0].text, /active/);
  const recalled = await request(4, "tools/call", { name: "pma_recall",
    arguments: { query: "MCP explicit memory" } });
  assert.match(recalled.result.content[0].text, /selected_count/);
  child.stdin.end();
  await once(child, "exit");
  assert.equal(stderr, "");
  await rm(root, { recursive: true });
});

